/**
 * Cohort 9A — Truthful read-only Control Center snapshot adapter.
 *
 * This module is the ONLY bridge between the authoritative SCOS backend
 * snapshot (generated by scos/control_center/control_center_snapshot.py and
 * served same-origin via /api/control-center-snapshot) and the cockpit view
 * models. It is LOCAL-ONLY and READ-ONLY:
 *
 *  - It never executes commands, approves/rejects, mutates queues, invokes
 *    HVS, renders, or writes persistence.
 *  - It never calls subprocess, opens sockets, or reaches external network.
 *  - It never imports Python modules or reads sqlite/JSONL directly.
 *  - Demo data is a SEPARATE constant dataset; it is never merged with live
 *    data and is never auto-enabled.
 *
 * Backend section vocabulary (mirrors the Python projection):
 *  - status:  AVAILABLE_WITH_DATA | AVAILABLE_EMPTY | UNAVAILABLE | DEGRADED | ERROR
 *  - available: boolean — false means the source could not be read (do NOT
 *    treat as zero/empty).
 */

export type SectionStatus =
  | "AVAILABLE_WITH_DATA"
  | "AVAILABLE_EMPTY"
  | "UNAVAILABLE"
  | "DEGRADED"
  | "ERROR";

export interface SnapshotSection<T> {
  available: boolean;
  status: SectionStatus;
  data: T | null;
  reason_code: string | null;
  observed_at: string;
}

export interface HealthData {
  health_status: string;
  artifact_count: number;
  event_count: number;
  command_record_count: number;
  audit_record_count: number;
  warning_count: number;
  blocker_count: number;
  source_coverage: [string, string][];
}

export interface QueueData {
  count: number;
  items: { command_id: string; command_type: string; approved_at: string }[];
}

export interface ApprovalData {
  approval_count: number;
  audit_record_count: number | null;
}

export interface EvidenceData {
  event_record_count: number;
  audit_record_count: number;
}

export interface ProjectData {
  state_tables_present: string[];
  has_dedicated_project_model: boolean;
}

export interface ActivityItem {
  activity_id: string;
  activity_type: string;
  status: string;
  summary: string;
  occurred_at: string;
}

export interface ActivityData {
  count: number;
  items: ActivityItem[];
}

export interface ControlCenterSnapshot {
  schema_version: number;
  snapshot_id: string;
  generated_at: string;
  source_mode: "LIVE_LOCAL_READ_ONLY" | "DEMO";
  health: SnapshotSection<HealthData>;
  queue_summary: SnapshotSection<QueueData>;
  approval_summary: SnapshotSection<ApprovalData>;
  project_summary: SnapshotSection<ProjectData>;
  evidence_summary: SnapshotSection<EvidenceData>;
  recent_activity: SnapshotSection<ActivityData>;
  degradation_reasons: string[];
}

export type DataMode = "LIVE" | "DEMO";

/**
 * Map a backend snapshot into cockpit-safe view models.
 * Unavailable sections yield null domain data so the UI can render an
 * explicit "unavailable" state instead of pretending the value is zero.
 */
export interface CockpitView {
  sourceMode: DataMode;
  observedAt: string;
  schemaVersion: number;
  health: {
    available: boolean;
    status: SectionStatus;
    healthStatus: string | null;
    warningCount: number | null;
    blockerCount: number | null;
    reasonCode: string | null;
  };
  queue: {
    available: boolean;
    status: SectionStatus;
    count: number | null;
    items: { command_id: string; command_type: string; approved_at: string }[] | null;
    reasonCode: string | null;
  };
  approvals: {
    available: boolean;
    status: SectionStatus;
    count: number | null;
    reasonCode: string | null;
  };
  evidence: {
    available: boolean;
    status: SectionStatus;
    eventCount: number | null;
    auditCount: number | null;
    reasonCode: string | null;
  };
  projects: {
    available: boolean;
    status: SectionStatus;
    hasDedicatedModel: boolean;
    stateTables: string[];
  };
  activity: {
    available: boolean;
    status: SectionStatus;
    count: number | null;
    items: ActivityItem[] | null;
  };
}

function emptyActivityItems(): ActivityItem[] | null {
  return null;
}

export function mapSnapshotToCockpit(
  snapshot: ControlCenterSnapshot,
  mode: DataMode,
): CockpitView {
  const health = snapshot.health;
  const queue = snapshot.queue_summary;
  const approvals = snapshot.approval_summary;
  const evidence = snapshot.evidence_summary;
  const projects = snapshot.project_summary;
  const activity = snapshot.recent_activity;

  return {
    sourceMode: mode,
    observedAt: snapshot.generated_at,
    schemaVersion: snapshot.schema_version,
    health: {
      available: health.available,
      status: health.status,
      healthStatus: health.data?.health_status ?? null,
      warningCount: health.data?.warning_count ?? null,
      blockerCount: health.data?.blocker_count ?? null,
      reasonCode: health.reason_code ?? null,
    },
    queue: {
      available: queue.available,
      status: queue.status,
      count: queue.data?.count ?? null,
      items: queue.data?.items ?? null,
      reasonCode: queue.reason_code ?? null,
    },
    approvals: {
      available: approvals.available,
      status: approvals.status,
      count: approvals.data?.approval_count ?? null,
      reasonCode: approvals.reason_code ?? null,
    },
    evidence: {
      available: evidence.available,
      status: evidence.status,
      eventCount: evidence.data?.event_record_count ?? null,
      auditCount: evidence.data?.audit_record_count ?? null,
      reasonCode: evidence.reason_code ?? null,
    },
    projects: {
      available: projects.available,
      status: projects.status,
      hasDedicatedModel: projects.data?.has_dedicated_project_model ?? false,
      stateTables: projects.data?.state_tables_present ?? [],
    },
    activity: {
      available: activity.available,
      status: activity.status,
      count: activity.data?.count ?? null,
      items: activity.data?.items ?? emptyActivityItems(),
    },
  };
}

