export const DEMO_LABEL = "DEMO DATA — NOT LIVE SYSTEM STATE";

/** Resolve the active view model from a data mode. Demo never falls back to live,
 *  and live failure never falls back to demo. */
export function resolveCockpitView(mode: DataMode, live: ControlCenterSnapshot | null): CockpitView {
  if (mode === "DEMO") {
    return mapSnapshotToCockpit(DEMO_SNAPSHOT, "DEMO");
  }
  // LIVE mode: if the live snapshot failed to load, report unavailable states
  // truthfully rather than substituting demo data.
  if (!live) {
    return mapSnapshotToCockpit(unavailableFallback(), "LIVE");
  }
  return mapSnapshotToCockpit(live, "LIVE");
}

function unavailableFallback(): ControlCenterSnapshot {
  const section = {
    available: false,
    status: "UNAVAILABLE" as SectionStatus,
    data: null,
    reason_code: "READ_FAILED",
    observed_at: new Date().toISOString(),
  };
  return {
    schema_version: 1,
    snapshot_id: "ccs-failed",
    generated_at: new Date().toISOString(),
    source_mode: "LIVE_LOCAL_READ_ONLY",
    health: { ...section },
    queue_summary: { ...section },
    approval_summary: { ...section },
    project_summary: { ...section },
    evidence_summary: { ...section },
    recent_activity: { ...section },
    degradation_reasons: ["READ_FAILED"],
  };
}

// ---------------------------------------------------------------------------
// React data hook (client-only). Reads the same-origin read-only transport,
// never reaches external network, never executes commands.
// ---------------------------------------------------------------------------

import { useCallback, useEffect, useRef, useState } from "react";

export type LoadState = "loading" | "ready" | "error";

export interface UseControlCenterData {
  mode: DataMode;
  setMode: (mode: DataMode) => void;
  view: CockpitView;
  loadState: LoadState;
  lastUpdatedAt: string | null;
  refresh: () => void;
  errorMessage: string | null;
}

export function useControlCenterData(initialMode: DataMode = "LIVE"): UseControlCenterData {
  const [mode, setMode] = useState<DataMode>(initialMode);
  const [live, setLive] = useState<ControlCenterSnapshot | null>(null);
  const [loadState, setLoadState] = useState<LoadState>("loading");
  const [lastUpdatedAt, setLastUpdatedAt] = useState<string | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  // Guard against overlapping/out-of-order requests.
  const requestSeq = useRef(0);

  const loadLive = useCallback(() => {
    const seq = ++requestSeq.current;
    setLoadState("loading");
    setErrorMessage(null);
    fetch("/api/control-center-snapshot", { method: "GET", cache: "no-store" })
      .then((res) => {
        if (!res.ok) throw new Error(`http_${res.status}`);
        return res.json();
      })
      .then((payload: ControlCenterSnapshot) => {
        // Ignore stale responses (newer request already in flight).
        if (seq !== requestSeq.current) return;
        setLive(payload);
        setLastUpdatedAt(payload.generated_at ?? new Date().toISOString());
        setLoadState("ready");
      })
      .catch((err: unknown) => {
        if (seq !== requestSeq.current) return;
        setLive(null);
        setErrorMessage(err instanceof Error ? err.message : "unknown_error");
        setLoadState("error");
      });
  }, []);

  useEffect(() => {
    if (mode === "LIVE") {
      loadLive();
    } else {
      // Demo is local; no fetch required.
      setLoadState("ready");
      setErrorMessage(null);
    }
  }, [mode, loadLive]);

  const view = resolveCockpitView(mode, live);
  const refresh = useCallback(() => {
    if (mode === "LIVE") loadLive();
  }, [mode, loadLive]);

  return { mode, setMode, view, loadState, lastUpdatedAt, refresh, errorMessage };
}
